#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct Node {
    long long key;
    long long value;
    struct Node *next;
} Node;

#define TABLE_SIZE 2000003
static Node *table[TABLE_SIZE];

static unsigned long long hash_key(long long x) {
    return (unsigned long long)x % TABLE_SIZE;
}

static long long get_memo(long long x) {
    unsigned long long h = hash_key(x);
    for (Node *p = table[h]; p; p = p->next) {
        if (p->key == x) return p->value;
    }
    return -1;
}

static void set_memo(long long x, long long v) {
    unsigned long long h = hash_key(x);
    Node *p = (Node*)malloc(sizeof(Node));
    p->key = x; p->value = v; p->next = table[h];
    table[h] = p;
}

static long long solve(long long n) {
    long long cached = get_memo(n);
    if (cached != -1) return cached;
    if (n < 12) {
        set_memo(n, n);
        return n;
    }
    long long res = solve(n/2) + solve(n/3) + solve(n/4);
    if (res < n) res = n;
    set_memo(n, res);
    return res;
}

int main() {
    long long n;
    while (scanf("%lld", &n) == 1) {
        printf("%lld\n", solve(n));
    }
    return 0;
}

