unordered_map<long long,long long> memo;

long long solve(long long n){
    if(n < 12) return n;
    auto it = memo.find(n);
    if(it != memo.end()) return it->second;
    long long val = solve(n/2) + solve(n/3) + solve(n/4);
    if(val < n) val = n;
    return memo[n] = val;
}

