#!/usr/bin/env python3
import sys
sys.setrecursionlimit(1000000)
memo = {i: i for i in range(12)}  # base cases 0..11

def solve(n):
    if n < 12:
        return n
    if n in memo:
        return memo[n]
    val = solve(n//2) + solve(n//3) + solve(n//4)
    if val < n:
        val = n
    memo[n] = val
    return val

out = []
for token in sys.stdin.read().split():
    n = int(token)
    out.append(str(solve(n)))
print('\n'.join(out))

